-- SEED — your 7 doctors (EN + AR). Department is a list (text[]).
-- Run AFTER migration-3.sql. Re-running safely updates by slug.
on conflict (slug) do update set name_en=excluded.name_en, name_ar=excluded.name_ar,
  specialty_en=excluded.specialty_en, specialty_ar=excluded.specialty_ar,
  bio_en=excluded.bio_en, bio_ar=excluded.bio_ar, image_url=excluded.image_url,
  department=excluded.department, sort_order=excluded.sort_order, is_active=excluded.is_active;
